230	function ptLineDist(
231	  p: { x: number; y: number },
232	  a: { x: number; y: number },
233	  b: { x: number; y: number },
234	): number {
235	  const dx = b.x - a.x,
236	    dy = b.y - a.y;
237	  if (dx === 0 && dy === 0) return Math.hypot(p.x - a.x, p.y - a.y);
238	  const t = ((p.x - a.x) * dx + (p.y - a.y) * dy) / (dx * dx + dy * dy);
239	  return Math.hypot(p.x - (a.x + t * dx), p.y - (a.y + t * dy));
240	}
