242	function rdpSimplify(
243	  pts: Array<{ x: number; y: number }>,
244	  eps: number,
245	): Array<{ x: number; y: number }> {
246	  if (pts.length <= 2) return pts;
247	  let maxD = 0,
248	    maxI = 0;
249	  for (let i = 1; i < pts.length - 1; i++) {
250	    const d = ptLineDist(pts[i], pts[0], pts[pts.length - 1]);
251	    if (d > maxD) {
252	      maxD = d;
253	      maxI = i;
254	    }
255	  }
256	  if (maxD > eps) {
257	    const l = rdpSimplify(pts.slice(0, maxI + 1), eps);
258	    const r = rdpSimplify(pts.slice(maxI), eps);
259	    return [...l.slice(0, -1), ...r];
260	  }
261	  return [pts[0], pts[pts.length - 1]];
262	}
