427	export function getNodeBounds(node: SceneNode): {
428	  x: number;
429	  y: number;
430	  w: number;
431	  h: number;
432	} {
433	  const { x, y } = node.transform.position;
434	  if (node.type === "primitive") {
435	    const p = node as Primitive;
436	    if (p.geometry.type === "rect")
437	      return { x, y, w: p.geometry.width, h: p.geometry.height };
438	    if (p.geometry.type === "ellipse")
439	      return {
440	        x: x - p.geometry.rx,
441	        y: y - p.geometry.ry,
442	        w: p.geometry.rx * 2,
443	        h: p.geometry.ry * 2,
444	      };
445	    if (p.geometry.type === "line") {
446	      const minX = Math.min(p.geometry.x1, p.geometry.x2);
447	      const minY = Math.min(p.geometry.y1, p.geometry.y2);
448	      return {
449	        x: x + minX,
450	        y: y + minY,
451	        w: Math.abs(p.geometry.x2 - p.geometry.x1) || 4,
452	        h: Math.abs(p.geometry.y2 - p.geometry.y1) || 4,
453	      };
454	    }
455	  }
456	  if (node.type === "text_block") {
457	    const tb = node as TextBlock;
458	    // Ensure minimum hit target size (40x20) for reliable right-click detection on small text
459	    const minW = 40,
460	      minH = 20;
461	    const w = Math.max(tb.maxWidth ?? 120, minW);
462	    const h = Math.max(tb.fontSize ? tb.fontSize * 2 : 20, minH);
463	    return { x, y, w, h };
464	  }
465	  if (node.type === "image") {
466	    const img = node as ImageNode;
467	    return { x, y, w: img.displayWidth, h: img.displayHeight };
468	  }
469	  if (node.type === "pipe") {
470	    const pipe = node as Pipe;
471	    if (pipe.waypoints && pipe.waypoints.length >= 2) {
472	      const xs = pipe.waypoints.map((p) => p.x);
473	      const ys = pipe.waypoints.map((p) => p.y);
474	      return {
475	        x: Math.min(...xs),
476	        y: Math.min(...ys),
477	        w: Math.max(...xs) - Math.min(...xs) || 4,
478	        h: Math.max(...ys) - Math.min(...ys) || 4,
479	      };
480	    }
481	  }
482	  if (node.type === "widget") {
483	    const wn = node as WidgetNode;
484	    return { x, y, w: wn.width, h: wn.height };
485	  }
486	  if (node.type === "embedded_svg") {
487	    const esn = node as EmbeddedSvgNode;
488	    return { x, y, w: esn.width || 64, h: esn.height || 64 };
489	  }
490	  if (node.type === "symbol_instance") {
491	    const si = node as SymbolInstance;
492	    const shapeData = useLibraryStore.getState().getShape(si.shapeRef.shapeId);
493	    const geo = shapeData?.sidecar.geometry;
494	    const naturalW = geo?.baseSize?.[0] ?? geo?.width ?? 64;
495	    const naturalH = geo?.baseSize?.[1] ?? geo?.height ?? 64;
496	    return {
497	      x,
498	      y,
499	      w: naturalW * (si.transform.scale.x ?? 1),
500	      h: naturalH * (si.transform.scale.y ?? 1),
501	    };
502	  }
503	  if (node.type === "stencil") {
504	    const st = node as Stencil;
505	    return { x, y, w: st.size?.width ?? 48, h: st.size?.height ?? 24 };
506	  }
507	  if (node.type === "display_element") {
508	    const de = node as DisplayElement;
509	    const cfg = de.config;
510	    switch (cfg.displayType) {
511	      case "text_readout": {
512	        const tCfg = cfg as TextReadoutConfig;
513	        const pnEnabled = tCfg.pointNameRow?.enabled ?? false;
514	        const dnEnabled = tCfg.displayNameRow?.enabled ?? false;
