const interactionRef = useRef<{
  type:
    | "none"
    | "drag"
    | "draw"
    | "pan"
    | "pipe"
    | "marquee"
    | "rotate"
    | "resize"
    | "freehand";
  startCanvasX: number;
  startCanvasY: number;
  startScreenX: number;
  startScreenY: number;
  startPanX: number;
  startPanY: number;
  originalPositions: Map<NodeId, { x: number; y: number }>;
  originalTransforms: Map<NodeId, Transform>;
  originalPivots: Map<NodeId, { x: number; y: number }>;
  // rotate-specific
  rotateCenter: { x: number; y: number };
  rotateStartAngle: number;
  rotatePivots: Map<NodeId, { x: number; y: number }>;
  rotateInitialTransforms: Map<NodeId, Transform>;
  // resize-specific
  resizeNodeId: NodeId;
  resizeHandle: ResizeHandle;
  resizeOrigBounds: { x: number; y: number; w: number; h: number };
  resizeOrigTransform: Transform;
  // multi-node resize
  resizeNodeIds: NodeId[];
  resizeNodeOrigTransforms: Map<NodeId, Transform>;
  resizeNodeOrigDims: Map<NodeId, { w: number; h: number }>;
  resizeOrigSelectionBBox: { x: number; y: number; w: number; h: number };
  deferredSingleSelectId: NodeId | null;
}>({
  type: "none",
  startCanvasX: 0,
  startCanvasY: 0,
  startScreenX: 0,
  startScreenY: 0,
  startPanX: 0,
  startPanY: 0,
  originalPositions: new Map(),
  originalTransforms: new Map(),
  originalPivots: new Map(),
  rotateCenter: { x: 0, y: 0 },
  rotateStartAngle: 0,
  rotatePivots: new Map(),
  rotateInitialTransforms: new Map(),
  resizeNodeId: "" as NodeId,
  resizeHandle: "se",
  resizeOrigBounds: { x: 0, y: 0, w: 0, h: 0 },
  resizeOrigTransform: {
    position: { x: 0, y: 0 },
    rotation: 0,
    scale: { x: 1, y: 1 },
    mirror: "none",
  },
  resizeNodeIds: [],
  resizeNodeOrigTransforms: new Map(),
  resizeNodeOrigDims: new Map(),
  resizeOrigSelectionBBox: { x: 0, y: 0, w: 0, h: 0 },
  // When mousedown lands on an already-selected node in a multi-select group,
  // selection change is deferred: if the pointer releases without dragging we
  // commit the single-select; if the user drags we move the whole group.
  deferredSingleSelectId: null as NodeId | null,
});

const handleMouseDown = useCallback(
  (e: React.MouseEvent) => {
    useGlobalSelectionStore.getState().setActiveZone("designer");
    // Middle mouse button → pan
    if (e.button === 1) {
      e.preventDefault();
      const vp = viewportRef.current;
      const inter = interactionRef.current;
      inter.type = "pan";
      inter.startScreenX = e.clientX;
      inter.startScreenY = e.clientY;
      inter.startPanX = vp.panX;
      inter.startPanY = vp.panY;
      return;
    }
    if (e.button !== 0) return;

    // ── Place mode: floating → confirming on click ───────────────────────
    if (placeModeRef.current?.phase === "floating") {
      const pm = placeModeRef.current;
      const rect = getRect();
      if (!rect) return;
      const vp = viewportRef.current;
      const cx = snap((e.clientX - rect.left - vp.panX) / vp.zoom);
      const cy = snap((e.clientY - rect.top - vp.panY) / vp.zoom);

      const dx = cx - pm.originCenter.x;
      const dy = cy - pm.originCenter.y;
      const shiftedNodes: SceneNode[] = pm.nodes.map((n) => ({
        ...n,
        transform: {
          ...n.transform,
          position: {
            x: n.transform.position.x + dx,
            y: n.transform.position.y + dy,
          },
        },
      }));

      const prePastePointer = useHistoryStore.getState().pointer;
      const oldIds = new Set(
        (useSceneStore.getState().doc?.children ?? []).map((n) => n.id),
      );
      executeCmd(new PasteNodesCommand(shiftedNodes, pm.expressions));
      const newDoc = useSceneStore.getState().doc;
      if (!newDoc) {
        setPlaceMode(null);
        return;
      }
      const pastedNodeIds = newDoc.children

