      {/* Vertical ruler (left) */}
      <svg
        style={{
          position: "absolute",
          top: RULER_SIZE,
          left: 0,
          width: RULER_SIZE,
          height: `calc(100% - ${RULER_SIZE}px)`,
          zIndex: 10,
          cursor: "e-resize",
          pointerEvents: "all",
        }}
        onMouseDown={(e) => startGuideCreate(e, "v")}
      >
        <rect
          width={RULER_SIZE}
          height="100%"
          fill="var(--io-surface-elevated)"
        />
        {renderTicks("v", H)}
      </svg>

      {/* Corner square */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          width: RULER_SIZE,
          height: RULER_SIZE,
          background: "var(--io-surface-elevated)",
          zIndex: 11,
          borderRight: "1px solid var(--io-border)",
          borderBottom: "1px solid var(--io-border)",
        }}
      />

      {/* User guides rendered over the canvas (screen-space) — RC-DES-17 */}
      {guidesVisible &&
        guides.map((g) => {
          const screenPos =
            g.axis === "v"
              ? g.position * zoom + panX + RULER_SIZE
              : g.position * zoom + panY + RULER_SIZE;

          const guideLineStyle: React.CSSProperties =
            g.axis === "v"
              ? {
                  position: "absolute",
                  top: RULER_SIZE,
                  left: screenPos,
                  width: 1,
                  height: `calc(100% - ${RULER_SIZE}px)`,
                  background: g.locked
                    ? "rgba(255,160,0,0.5)"
                    : "rgba(0,200,255,0.5)",
                  cursor: g.locked ? "not-allowed" : "ew-resize",
                  zIndex: 9,
                  pointerEvents: "all",
                }
              : {
                  position: "absolute",
                  top: screenPos,
                  left: RULER_SIZE,
                  height: 1,
                  width: `calc(100% - ${RULER_SIZE}px)`,
                  background: g.locked
