return (
  <ContextMenuPrimitive.Portal>
    <ContextMenuPrimitive.Content style={contentStyle}>
      {/* Test mode controls — shown at the top whenever the canvas is in test mode */}
      {testMode && (
        <>
          <ContextMenuPrimitive.Item
            style={itemStyle}
            onSelect={() =>
              useUiStore.getState().setTestModePaused(!testModePaused)
            }
          >
            {testModePaused ? "▶ Resume" : "⏸ Pause"}
          </ContextMenuPrimitive.Item>
          <ContextMenuPrimitive.Item
            style={{ ...itemStyle, color: "var(--io-error, #ef4444)" }}
            onSelect={() => useUiStore.getState().setTestMode(false)}
          >
            Exit Test Mode
          </ContextMenuPrimitive.Item>
          <ContextMenuPrimitive.Separator style={sepStyle} />
        </>
      )}
      {nodeId === null ? (
        // ----------------------------------------------------------------
        // RC-DES-1: Empty-canvas context menu
        // ----------------------------------------------------------------
        <>
          {/* Paste */}
          <ContextMenuPrimitive.Item
            style={itemStyle}
            disabled={!ioClipboardCurrent}
            onSelect={() => void pasteDefault()}
          >
            Paste
          </ContextMenuPrimitive.Item>

          <ContextMenuPrimitive.Sub>
            <ContextMenuPrimitive.SubTrigger
              style={{
                ...itemStyle,
                ...(designerCurrentModes.length === 0
                  ? { opacity: 0.4, pointerEvents: "none" }
                  : {}),
              }}
              disabled={designerCurrentModes.length === 0}
            >
              Paste as…
            </ContextMenuPrimitive.SubTrigger>
            <ContextMenuPrimitive.Portal>
              <ContextMenuPrimitive.SubContent style={subContentStyle}>
                {DESIGNER_PASTE_AS_ORDER.map(({ mode, label }) => {
                  const available = designerCurrentModes.includes(mode);
                  return (
                    <ContextMenuPrimitive.Item
                      key={mode}
                      style={{
                        ...itemStyle,
                        ...(available
                          ? {}
                          : { opacity: 0.4, pointerEvents: "none" }),
                      }}
                      disabled={!available}
                      onSelect={() => void pasteAs(mode, "current")}
                    >
                      {label}
                    </ContextMenuPrimitive.Item>
                  );
                })}
              </ContextMenuPrimitive.SubContent>
            </ContextMenuPrimitive.Portal>
          </ContextMenuPrimitive.Sub>

          <ContextMenuPrimitive.Separator style={sepStyle} />

          {/* Select All — disabled when doc has no children */}
          <ContextMenuPrimitive.Item
            style={itemStyle}
            disabled={!hasDoc || (doc?.children.length ?? 0) === 0}
            onSelect={() => {
              if (!doc) return;
              const allIds = doc.children
                .filter((n) => n.visible && !n.locked)
                .map((n) => n.id);
              selectedIdsRef.current = new Set(allIds);
              useUiStore.getState().setSelectedNodes(allIds);
            }}
          >
            Select All
          </ContextMenuPrimitive.Item>

          <ContextMenuPrimitive.Separator style={sepStyle} />

          {/* Grid submenu */}
          <ContextMenuPrimitive.Sub>
            <ContextMenuPrimitive.SubTrigger style={itemStyle}>
              Grid
            </ContextMenuPrimitive.SubTrigger>
            <ContextMenuPrimitive.Portal>
              <ContextMenuPrimitive.SubContent style={subContentStyle}>
                {/* Show Grid toggle */}
                <ContextMenuPrimitive.Item
                  style={itemStyle}
                  onSelect={() => setGrid(!gridVisible, gridSize)}
                >
                  {gridVisible ? "Hide Grid" : "Show Grid"}
                </ContextMenuPrimitive.Item>

                {/* Snap to Grid toggle */}
                <ContextMenuPrimitive.Item
                  style={itemStyle}
                  onSelect={() => setSnap(!snapToGrid)}
                >
                  {snapToGrid
                    ? "Disable Snap to Grid"
                    : "Enable Snap to Grid"}
                </ContextMenuPrimitive.Item>

                <ContextMenuPrimitive.Separator style={sepStyle} />

                {/* Grid Size sub-submenu */}
                <ContextMenuPrimitive.Sub>
                  <ContextMenuPrimitive.SubTrigger style={itemStyle}>
                    Grid Size ({gridSize}px)
                  </ContextMenuPrimitive.SubTrigger>
                  <ContextMenuPrimitive.Portal>
                    <ContextMenuPrimitive.SubContent style={subContentStyle}>
                      {GRID_SIZE_PRESETS.map((size) => (
                        <ContextMenuPrimitive.Item
                          key={size}
                          style={itemStyle}
                          disabled={gridSize === size}
                          onSelect={() => setGrid(gridVisible, size)}
                        >
                          {gridSize === size ? `✓ ${size}px` : `${size}px`}
                        </ContextMenuPrimitive.Item>
                      ))}
                    </ContextMenuPrimitive.SubContent>
                  </ContextMenuPrimitive.Portal>
                </ContextMenuPrimitive.Sub>
              </ContextMenuPrimitive.SubContent>
            </ContextMenuPrimitive.Portal>
          </ContextMenuPrimitive.Sub>

          {/* Zoom submenu */}
          <ContextMenuPrimitive.Sub>
            <ContextMenuPrimitive.SubTrigger style={itemStyle}>
              Zoom
            </ContextMenuPrimitive.SubTrigger>
            <ContextMenuPrimitive.Portal>
              <ContextMenuPrimitive.SubContent style={subContentStyle}>
                <ContextMenuPrimitive.Item
                  style={itemStyle}
                  onSelect={() => zoomTo(zoom * 1.25)}
                >
                  Zoom In
                </ContextMenuPrimitive.Item>

                <ContextMenuPrimitive.Item
                  style={itemStyle}
                  onSelect={() => zoomTo(zoom * 0.8)}
                >
                  Zoom Out
                </ContextMenuPrimitive.Item>

                <ContextMenuPrimitive.Item
                  style={itemStyle}
                  onSelect={() => {
                    const d = docRef.current;
                    const el = containerRef.current;
                    if (d && el) {
                      const r = el.getBoundingClientRect();
                      fitToCanvas(
                        d.canvas.width,
                        d.canvas.height,
                        r.width,
                        r.height,
                      );
                    }
                  }}
                >
                  Zoom to Fit
                </ContextMenuPrimitive.Item>

                <ContextMenuPrimitive.Item
                  style={itemStyle}
                  onSelect={() => zoomTo(1.0)}
                >
                  Zoom to 100%
                </ContextMenuPrimitive.Item>
              </ContextMenuPrimitive.SubContent>
            </ContextMenuPrimitive.Portal>
          </ContextMenuPrimitive.Sub>

          <ContextMenuPrimitive.Separator style={sepStyle} />

          {/* Canvas Properties */}
          <ContextMenuPrimitive.Item
            style={itemStyle}
            onSelect={() => onPropertiesOpen?.()}

