0	/**
1	 * CanvasPropertiesDialog.tsx
2	 *
3	 * Floating dialog for canvas properties:
4	 *   - Canvas width / height (with proportional lock + preset chips)
5	 *   - Auto-grow vertically (report mode)
6	 *   - Background color
7	 *   - Grid size
8	 *
9	 * Changes are live (no "Apply" button). W/H changes are debounced 500ms.
10	 * Out-of-bounds warning shows count of nodes that would fall outside the new canvas.
11	 */
12	
13	import React, { useCallback, useEffect, useRef, useState } from "react";
14	import {
15	  useSceneStore,
16	  useHistoryStore,
17	  useUiStore,
18	} from "../../../store/designer";
19	import { ChangePropertyCommand } from "../../../shared/graphics/commands";
20	import { getNodeBounds } from "../DesignerCanvas";
21	import type { SceneNode } from "../../../shared/types/graphics";
22	import { AspectPreset, ASPECT_PRESETS, ChainLinkIcon } from "./canvasPresets";
23	
24	const GRID_OPTIONS = [4, 8, 10, 16, 32];
25	
26	// ---------------------------------------------------------------------------
27	// Count nodes outside the given bounds
28	// ---------------------------------------------------------------------------
29	
30	function countOutOfBounds(
31	  nodes: SceneNode[],
32	  w: number,
33	  h: number,
34	): { count: number; ids: string[] } {
35	  const ids: string[] = [];
36	  for (const node of nodes) {
37	    const bounds = getNodeBounds(node);
38	    const right = bounds.x + bounds.w;
39	    const bottom = bounds.y + bounds.h;
40	    if (bounds.x < 0 || bounds.y < 0 || right > w || bottom > h) {
41	      ids.push(node.id);
42	    }
43	  }
44	  return { count: ids.length, ids };
45	}
46	
47	// ---------------------------------------------------------------------------
48	// Props
49	// ---------------------------------------------------------------------------
50	
51	export interface CanvasPropertiesDialogProps {
52	  onClose: () => void;
53	}
54	
55	// ---------------------------------------------------------------------------
56	// Component
57	// ---------------------------------------------------------------------------
58	
59	export default function CanvasPropertiesDialog({
60	  onClose,
61	}: CanvasPropertiesDialogProps) {
62	  const doc = useSceneStore((s) => s.doc);
63	  const execute = useSceneStore((s) => s.execute);
64	  const push = useHistoryStore((s) => s.push);
65	
66	  const executeCmd = useCallback(
67	    (cmd: ChangePropertyCommand) => {
68	      if (!doc) return;
69	      const before = doc;
70	      execute(cmd);
71	      push(cmd, before);
72	    },
73	    [doc, execute, push],
74	  );
75	
76	  // Local state (mirrors doc values; updates live)
77	  const [width, setWidth] = useState<number>(doc?.canvas.width ?? 1920);
78	  const [height, setHeight] = useState<number>(doc?.canvas.height ?? 1080);
79	  const [autoHeight, setAutoHeight] = useState<boolean>(
80	    doc?.canvas.autoHeight ?? false,
81	  );
82	  const [bgColor, setBgColor] = useState<string>(
83	    doc?.canvas.backgroundColor ?? "var(--io-accent-foreground)",
84	  );
85	  const [gridSize, setGridSize] = useState<number>(doc?.metadata.gridSize ?? 8);
86	  const [proportionalLock, setProportionalLock] = useState(false);
87	
88	  // Active preset chip
89	  const [activePreset, setActivePreset] = useState<string | null>(() => {
90	    if (!doc) return null;
91	    const match = ASPECT_PRESETS.find(
92	      (p) => p.width === doc.canvas.width && p.height === doc.canvas.height,
93	    );
94	    return match ? match.label : null;
