const GROUP_LABELS: Record<string, string> = {
  actuator: "Actuator",
  "fail-indicator": "Fail Position",
  agitator: "Agitator Type",
  support: "Support Type",
};

// Re-use the canonical constants from ShapeDropDialog (single source of truth)
